                            placeholder={appMode === 'generate' ? "e.g., a photorealistic portrait of an astronaut on a horse on Mars" : undefined}
                        />
                        {prompt.trim().length > 0 && !isLoading && (
                            <button
                                onClick={handleImprovePrompt}
