                                </div>
                            </div>
                        ) : ( 
                             <ImageDisplay 
                                imageUrl={currentResult || currentImage?.url} 
                                originalImageUrl={currentImage?.url}
                                isLoading={isLoading && !currentResult} 
                                onViewFullscreen={setFullscreenImageUrl}
