import React, { useState, useRef, useCallback } from 'react';
import type { ImageFile } from '../types';
import PromptInput from './PromptInput';

interface PictureMergerModalProps {
  image: ImageFile | null; // Current active image (can be used as default subject)
  onClose: () => void;
  onApply: (subjectImage: ImageFile, backgroundImage: ImageFile, mergerPrompt: string) => void;
}

const PictureMergerModal: React.FC<PictureMergerModalProps> = ({ image, onClose, onApply }) => {
  const [subjectImage, setSubjectImage] = useState<ImageFile | null>(image);
  const [backgroundImage, setBackgroundImage] = useState<ImageFile | null>(null);
  const [mergerPrompt, setMergerPrompt] = useState('');
  const [isUploading, setIsUploading] = useState<'subject' | 'background' | null>(null);

  const processFile = useCallback(async (file: File | null, type: 'subject' | 'background') => {
    if (!file || !file.type.startsWith('image/')) return;

    setIsUploading(type);

    try {
      const fileData = await new Promise<ImageFile>((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const url = reader.result as string;
          const base64 = url.split(',')[1];
          resolve({ url, base64, mimeType: file.type });
        };
        reader.onerror = (error) => reject(error);
        reader.readAsDataURL(file);
      });
      if (type === 'subject') setSubjectImage(fileData);
      else setBackgroundImage(fileData);
    } catch (error) {
      console.error(`Error processing ${type} image:`, error);
    } finally {
      setIsUploading(null);
    }
  }, []);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  };

  const renderDropZone = (type: 'subject' | 'background', currentImg: ImageFile | null) => {
    const isLoading = isUploading === type;
    const label = type === 'subject' ? 'Subject (Person)' : 'New Background';
    const icon = type === 'subject' ? (
        <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
    ) : (
        <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
    );

    return (
      <div className="flex flex-col items-center gap-3 w-full">
        <h3 className="font-semibold text-lg text-[--color-text-secondary]">{label}</h3>
        <div className="w-full aspect-square">
          <label
            className={`w-full h-full border-2 border-dashed rounded-lg flex flex-col justify-center items-center cursor-pointer transition-all duration-300 overflow-hidden relative
              ${isLoading ? 'border-[--color-primary] bg-[--color-surface-2]/50' : 'border-[--color-border] hover:border-[--color-primary] hover:bg-[--color-surface-2]/50'}
            `}
            onDragOver={handleDragOver}
            onDrop={(e) => {
                e.preventDefault();
                processFile(e.dataTransfer.files?.[0] || null, type);
            }}
          >
            <input
              type="file"
              onChange={(e) => processFile(e.target.files?.[0] || null, type)}
              accept="image/*"
              className="hidden"
            />
            {isLoading ? (
               <div className="text-center text-[--color-text-tertiary] animate-pulse">Processing...</div>
            ) : currentImg ? (
                <img src={currentImg.url} alt={label} className="w-full h-full object-contain animate-fade-in" />
            ) : (
              <div className="text-center text-[--color-text-tertiary] p-4">
                {icon}
                <p className="mt-2 text-sm font-semibold">Upload {label}</p>
                <p className="text-xs">Drag & drop or click</p>
              </div>
            )}
          </label>
        </div>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-[--color-bg]/80 flex flex-col justify-center items-center z-50 backdrop-blur-lg animate-fade-in p-4" onClick={onClose}>
      <div className="bg-[--color-surface-1] border border-[--color-border] rounded-lg shadow-2xl w-full max-w-4xl h-full max-h-[90vh] flex flex-col" onClick={(e) => e.stopPropagation()}>
        <header className="flex-shrink-0 flex items-center justify-between p-4 border-b border-[--color-border]">
          <h2 className="text-2xl font-bold text-[--color-text-primary] flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 text-[--color-primary]" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
            </svg>
            AI Picture Merger
          </h2>
          <button onClick={onClose} className="text-[--color-text-tertiary] text-3xl hover:text-[--color-text-primary] transition-all" aria-label="Close">&times;</button>
        </header>

        <div className="flex-grow p-6 overflow-y-auto">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-start">
            {renderDropZone('subject', subjectImage)}
            {renderDropZone('background', backgroundImage)}
          </div>

          <div className="mt-8 bg-[--color-surface-inset]/30 p-4 rounded-xl border border-[--color-border]/30">
              <label htmlFor="merger-prompt" className="block text-sm font-bold text-[--color-primary] mb-2 uppercase tracking-wider">
                  Custom Blend Instructions (Optional)
              </label>
              <PromptInput
                  id="merger-prompt"
                  prompt={mergerPrompt}
                  setPrompt={setMergerPrompt}
                  isDisabled={!subjectImage || !backgroundImage}
                  rows={2}
                  placeholder="e.g., 'Place him sitting on the bench in the background', 'Make her look like she belongs in this forest'"
              />
              <p className="text-xs text-[--color-text-tertiary] mt-3 leading-relaxed">
                  <span className="text-[--color-primary] font-bold">Default Behavior:</span> The AI will deeply analyze both images, extract the person from the subject image while <span className="text-[--color-text-primary]">100% preserving their face, body, clothing, and expression</span>, and realistically integrate them into the background with matching lighting and shadows.
              </p>
          </div>
        </div>

        <footer className="flex-shrink-0 flex justify-end items-center gap-4 p-4 border-t border-[--color-border] bg-[--color-surface-1]/50">
          <button onClick={onClose} className="py-2.5 px-6 bg-[--color-surface-3] hover:bg-[--color-text-placeholder] text-[--color-text-primary] font-bold rounded-xl transition-all">Cancel</button>
          <button 
            onClick={() => subjectImage && backgroundImage && onApply(subjectImage, backgroundImage, mergerPrompt)} 
            disabled={!subjectImage || !backgroundImage || !!isUploading} 
            className="py-2.5 px-8 bg-gradient-to-r from-[--color-primary] to-[--color-secondary] text-white font-bold rounded-xl shadow-lg disabled:opacity-50 disabled:cursor-not-allowed transform hover:scale-[1.02] active:scale-95 transition-all"
          >
            🚀 Merge Masterpiece
          </button>
        </footer>
      </div>
    </div>
  );
};

export default PictureMergerModal;

