                                title={tool.title}
                              >
                                <span className="text-2xl" role="img" aria-label={tool.label}>{tool.emoji}</span>
                                <p className="text-xs font-semibold mt-1 text-[--color-text-secondary]">{tool.label}</p>
                              </button>
